#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 13
#define MAX_T 13

int dx[] = {0, 0, 1, -1};
int dy[] = {1, -1, 0, 0};

int solveMaze(int n, char maze[MAX_N][MAX_N]) {
    int totalTreasures = 0;
    int treasurePositions[MAX_T][2];

    // Identify treasures and map them to bits
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            if (maze[i][j] == '*') {
                treasurePositions[totalTreasures][0] = i;
                treasurePositions[totalTreasures][1] = j;
                totalTreasures++;
            }
        }
    }

    int allTreasuresMask = (1 << totalTreasures) - 1;

    // BFS Queue
    int queue[MAX_N * MAX_N * (1 << totalTreasures)][4];
    int front = 0, rear = 0;
    queue[rear][0] = 0;
    queue[rear][1] = 0;
    queue[rear][2] = 0;
    queue[rear][3] = 0;
    rear++;

    int visited[MAX_N][MAX_N][1 << totalTreasures];
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            for (int k = 0; k < (1 << totalTreasures); ++k) {
                visited[i][j][k] = 0;
            }
        }
    }
    visited[0][0][0] = 1;

    while (front < rear) {
        int x = queue[front][0];
        int y = queue[front][1];
        int collected = queue[front][2];
        int time = queue[front][3];
        front++;

        // Collect a treasure if at the position
        for (int t = 0; t < totalTreasures; ++t) {
            if (maze[x][y] == '*' && x == treasurePositions[t][0] && y == treasurePositions[t][1]) {
                collected |= (1 << t);
            }
        }

        // Check if all treasures collected and reached end
        if (collected == allTreasuresMask && x == n - 1 && y == n - 1) {
            return time;
        }

        // Explore all four directions
        for (int dir = 0; dir < 4; ++dir) {
            int nx = x + dx[dir];
            int ny = y + dy[dir];

            if (nx >= 0 && nx < n && ny >= 0 && ny < n && maze[nx][ny] != '#' && !visited[nx][ny][collected]) {
                visited[nx][ny][collected] = 1;
                queue[rear][0] = nx;
                queue[rear][1] = ny;
                queue[rear][2] = collected;
                queue[rear][3] = time + 1;
                rear++;
            }
        }
    }

    return -1; // If destination is not reachable
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        char maze[MAX_N][MAX_N];
        for (int i = 0; i < N; ++i) {
            scanf("%s", maze[i]);
        }
        printf("%d\n", solveMaze(N, maze));
    }
    return 0;
}

