import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;

public class Main {
    static int[] dx = {0, 0, 1, -1};
    static int[] dy = {1, -1, 0, 0};

    public static int solveMaze(int n, char[][] maze) {
        int totalTreasures = 0;
        int[][] treasurePositions = new int[13][2];

        // Identify treasures and map them to bits
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                if (maze[i][j] == '*') {
                    treasurePositions[totalTreasures][0] = i;
                    treasurePositions[totalTreasures][1] = j;
                    totalTreasures++;
                }
            }
        }

        int allTreasuresMask = (1 << totalTreasures) - 1;

        // BFS Queue
        Queue<int[]> q = new LinkedList<>();
        q.add(new int[] {0, 0, 0, 0}); // (x, y, collected_bitmask, time)
        boolean[][][] visited = new boolean[n][n][1 << totalTreasures];
        visited[0][0][0] = true;

        while (!q.isEmpty()) {
            int[] state = q.poll();
            int x = state[0];
            int y = state[1];
            int collected = state[2];
            int time = state[3];

            // Collect a treasure if at the position
            for (int t = 0; t < totalTreasures; ++t) {
                if (maze[x][y] == '*' && x == treasurePositions[t][0] && y == treasurePositions[t][1]) {
                    collected |= (1 << t);
                }
            }

            // Check if all treasures collected and reached end
            if (collected == allTreasuresMask && x == n - 1 && y == n - 1) {
                return time;
            }

            // Explore all four directions
            for (int dir = 0; dir < 4; ++dir) {
                int nx = x + dx[dir];
                int ny = y + dy[dir];

                if (nx >= 0 && nx < n && ny >= 0 && ny < n && maze[nx][ny] != '#' && !visited[nx][ny][collected]) {
                    visited[nx][ny][collected] = true;
                    q.add(new int[] {nx, ny, collected, time + 1});
                }
            }
        }

        return -1; // If destination is not reachable
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            char[][] maze = new char[N][N];
            for (int i = 0; i < N; ++i) {
                maze[i] = sc.next().toCharArray();
            }
            System.out.println(solveMaze(N, maze));
        }
    }
}

