    let treasurePositions = [];

    // Identify treasures and map them to bits
    for (let i = 0; i < n; ++i) {
        for (let j = 0; j < n; ++j) {
            if (maze[i][j] === '*') {
                treasurePositions.push([i, j]);
                totalTreasures++;
            }
        }
    }

    let allTreasuresMask = (1 << totalTreasures) - 1;

    // BFS Queue
    let q = [[0, 0, 0, 0]]; // (x, y, collected_bitmask, time)
    let visited = Array(n).fill(0).map(() => Array(n).fill(0).map(() => Array(1 << totalTreasures).fill(false)));
    visited[0][0][0] = true;

    while (q.length > 0) {
        let [x, y, collected, time] = q.shift();

        // Collect a treasure if at the position
        for (let t = 0; t < treasurePositions.length; ++t) {
            if (maze[x][y] === '*' && x === treasurePositions[t][0] && y === treasurePositions[t][1]) {
                collected |= (1 << t);
            }
        }

        // Check if all treasures collected and reached end
        if (collected === allTreasuresMask && x === n - 1 && y === n - 1) {
            return time;
        }

        // Explore all four directions
        for (let dir = 0; dir < 4; ++dir) {
            let nx = x + DX[dir];
            let ny = y + DY[dir];

            if (nx >= 0 && nx < n && ny >= 0 && ny < n && maze[nx][ny] !== '#' && !visited[nx][ny][collected]) {
                visited[nx][ny][collected] = true;
                q.push([nx, ny, collected, time + 1]);
            }
        }
    }

    return -1; // If destination is not reachable
}

